-- Relational SQL Server schema matching the converted domain model.
CREATE TABLE OrganizationEntities (Id INT IDENTITY PRIMARY KEY, Name NVARCHAR(180) NOT NULL, IsActive BIT NOT NULL DEFAULT 1);
CREATE TABLE Departments (Id INT IDENTITY PRIMARY KEY, Name NVARCHAR(150) NOT NULL, EntityId INT NOT NULL REFERENCES OrganizationEntities(Id), IsActive BIT NOT NULL DEFAULT 1);
CREATE TABLE JobTitles (Id INT IDENTITY PRIMARY KEY, Name NVARCHAR(150) NOT NULL, UserName NVARCHAR(150) NULL, DepartmentId INT NULL REFERENCES Departments(Id), IsActive BIT NOT NULL DEFAULT 1);
CREATE TABLE DepartmentJobTitles (Id INT IDENTITY PRIMARY KEY, DepartmentId INT NOT NULL REFERENCES Departments(Id), JobTitleId INT NOT NULL REFERENCES JobTitles(Id), IsManagerTitle BIT NOT NULL DEFAULT 0, IsActive BIT NOT NULL DEFAULT 1);
CREATE TABLE Employees (Id INT IDENTITY PRIMARY KEY, FullName NVARCHAR(200) NOT NULL, NationalId NVARCHAR(20) NOT NULL UNIQUE, EmployeeCode NVARCHAR(30) NOT NULL, UserName NVARCHAR(30) NOT NULL, PasswordHash NVARCHAR(MAX) NOT NULL, MustChangePassword BIT NOT NULL DEFAULT 1, Email NVARCHAR(120) NULL, JobTitleId INT NOT NULL REFERENCES JobTitles(Id), DepartmentId INT NOT NULL REFERENCES Departments(Id), DepartmentJobTitleId INT NULL REFERENCES DepartmentJobTitles(Id), HireDate DATE NOT NULL, Role NVARCHAR(60) NOT NULL, ManagerId INT NULL REFERENCES Employees(Id), IsActive BIT NOT NULL DEFAULT 1);
CREATE TABLE EvaluationCycles (Id INT IDENTITY PRIMARY KEY, Name NVARCHAR(200) NOT NULL, StartDate DATE NOT NULL, EndDate DATE NOT NULL, IsActive BIT NOT NULL DEFAULT 0, IsStarted BIT NOT NULL DEFAULT 0, IsTesting BIT NOT NULL DEFAULT 0, IsHrApproved BIT NOT NULL DEFAULT 0, IsPublished BIT NOT NULL DEFAULT 0, VariationRate DECIMAL(9,2) NOT NULL DEFAULT 20, ResultComment NVARCHAR(MAX) NULL, HrApprovedAt DATETIME2 NULL, GrievanceStartDate DATE NULL, GrievanceEndDate DATE NULL);
CREATE TABLE EvaluationTemplates (Id INT IDENTITY PRIMARY KEY, Name NVARCHAR(150) NOT NULL, CycleId INT NULL REFERENCES EvaluationCycles(Id), JobTitleId INT NOT NULL REFERENCES JobTitles(Id), DepartmentJobTitleId INT NULL REFERENCES DepartmentJobTitles(Id), TargetEmployeeId INT NULL REFERENCES Employees(Id), TasksSectionWeight DECIMAL(9,2) NOT NULL DEFAULT 0, BehaviorsSectionWeight DECIMAL(9,2) NOT NULL DEFAULT 100, Type NVARCHAR(80) NOT NULL);
CREATE TABLE TemplateItems (Id INT IDENTITY PRIMARY KEY, EvaluationTemplateId INT NOT NULL REFERENCES EvaluationTemplates(Id) ON DELETE CASCADE, IsTask BIT NOT NULL, Name NVARCHAR(300) NOT NULL, Description NVARCHAR(MAX) NULL, Weight DECIMAL(9,2) NOT NULL);
CREATE TABLE PeerAssignments (Id INT IDENTITY PRIMARY KEY, CycleId INT NOT NULL REFERENCES EvaluationCycles(Id), EvaluatorId INT NOT NULL REFERENCES Employees(Id), EvaluateeId INT NOT NULL REFERENCES Employees(Id), CONSTRAINT UQ_PeerAssignments UNIQUE (CycleId, EvaluatorId, EvaluateeId));
CREATE TABLE Evaluations (Id INT IDENTITY PRIMARY KEY, IsDeleted BIT NOT NULL DEFAULT 0, CycleId INT NOT NULL REFERENCES EvaluationCycles(Id), EvaluatorId INT NOT NULL REFERENCES Employees(Id), EvaluateeId INT NOT NULL REFERENCES Employees(Id), Type NVARCHAR(80) NOT NULL, Status NVARCHAR(60) NOT NULL, TasksScore DECIMAL(9,2) NOT NULL DEFAULT 0, BehaviorsScore DECIMAL(9,2) NOT NULL DEFAULT 0, TotalScore DECIMAL(9,2) NOT NULL DEFAULT 0, Strengths NVARCHAR(MAX) NULL, Weaknesses NVARCHAR(MAX) NULL, Notes NVARCHAR(MAX) NULL, Recommendations NVARCHAR(MAX) NULL, HasAppeal BIT NOT NULL DEFAULT 0, AppealReason NVARCHAR(MAX) NULL, AppealDate DATETIME2 NULL, CreatedAt DATETIME2 NOT NULL DEFAULT SYSDATETIME(), SubmittedAt DATETIME2 NULL, CONSTRAINT UQ_Evaluations UNIQUE (CycleId, EvaluatorId, EvaluateeId, Type));
CREATE TABLE EvaluationScores (Id INT IDENTITY PRIMARY KEY, EvaluationId INT NOT NULL REFERENCES Evaluations(Id) ON DELETE CASCADE, TemplateItemId INT NOT NULL REFERENCES TemplateItems(Id), Score DECIMAL(9,2) NOT NULL, WeightedScore DECIMAL(9,2) NOT NULL);
CREATE TABLE EvaluationResultAdjustments (Id INT IDENTITY PRIMARY KEY, CycleId INT NOT NULL REFERENCES EvaluationCycles(Id), EmployeeId INT NOT NULL REFERENCES Employees(Id), AdjustedFinalScore DECIMAL(9,2) NULL, AdjustmentNotes NVARCHAR(MAX) NULL, StrengthsHighlights NVARCHAR(MAX) NULL, ImprovementPoints NVARCHAR(MAX) NULL, ResultStatus NVARCHAR(60) NOT NULL, UpdatedById INT NULL REFERENCES Employees(Id), CreatedAt DATETIME2 NOT NULL DEFAULT SYSDATETIME(), UpdatedAt DATETIME2 NULL, CONSTRAINT UQ_ResultAdjustments UNIQUE (CycleId, EmployeeId));
CREATE TABLE GrievanceRequests (Id INT IDENTITY PRIMARY KEY, CycleId INT NOT NULL REFERENCES EvaluationCycles(Id), EmployeeId INT NOT NULL REFERENCES Employees(Id), Reason NVARCHAR(MAX) NOT NULL, Status NVARCHAR(60) NOT NULL, HrReply NVARCHAR(MAX) NULL, AttachmentPath NVARCHAR(500) NULL, IsResultAccepted BIT NOT NULL DEFAULT 0, AllowsRevision BIT NOT NULL DEFAULT 0, CreatedAt DATETIME2 NOT NULL DEFAULT SYSDATETIME(), ReviewedAt DATETIME2 NULL, ReviewedById INT NULL REFERENCES Employees(Id));
CREATE TABLE EvaluationSettings (Id INT PRIMARY KEY DEFAULT 1, ItemTasksWeight DECIMAL(9,2) NOT NULL DEFAULT 70, ItemBehaviorsWeight DECIMAL(9,2) NOT NULL DEFAULT 30, FinalManagerWeight DECIMAL(9,2) NOT NULL DEFAULT 70, FinalSelfWeight DECIMAL(9,2) NOT NULL DEFAULT 10, FinalPeerWeight DECIMAL(9,2) NOT NULL DEFAULT 20);
CREATE TABLE ActivityLogs (Id INT IDENTITY PRIMARY KEY, UserId INT NULL, UserName NVARCHAR(200) NULL, ActionType NVARCHAR(100) NOT NULL, Description NVARCHAR(MAX) NULL, EntityName NVARCHAR(120) NULL, EntityId INT NULL, SnapshotJson NVARCHAR(MAX) NULL, CreatedAt DATETIME2 NOT NULL DEFAULT SYSDATETIME(), IsReverted BIT NOT NULL DEFAULT 0);
INSERT INTO EvaluationSettings (Id) SELECT 1 WHERE NOT EXISTS (SELECT 1 FROM EvaluationSettings WHERE Id = 1);
